import React, { createContext, useContext, useState, useCallback, useEffect } from "react";
import { authAPI, getToken, clearToken } from "../utils/api";

const AuthContext = createContext(null);

export function AuthProvider({ children }) {
  const [user,    setUser]    = useState(null);
  const [token,   setTokenSt] = useState(null);
  const [loading, setLoading] = useState(true);

  /* Restaurar sesión al montar */
  useEffect(() => {
    const savedToken = getToken();
    const savedUser  = localStorage.getItem("sicops_user");
    if (savedToken && savedUser) {
      try {
        setTokenSt(savedToken);
        setUser(JSON.parse(savedUser));
      } catch {
        clearToken();
      }
    }
    setLoading(false);
  }, []);

  const login = useCallback(async (email, password) => {
    try {
      const result = await authAPI.login(email, password);
      // authAPI.login ya llamó setToken(result.token) internamente
      setTokenSt(result.token);
      setUser(result.user);
      localStorage.setItem("sicops_user", JSON.stringify(result.user));
      return { success: true };
    } catch (err) {
      return {
        success: false,
        error:   err.message || "Error al iniciar sesión",
        code:    err.code    || null,
      };
    }
  }, []);

  const logout = useCallback(async () => {
    // No esperamos la respuesta del backend para no bloquear la UI
    try { authAPI.logout(); } catch { /* ignorar */ }
    setUser(null);
    setTokenSt(null);
    clearToken();
  }, []);

  const isAuthenticated = !!token;

  return (
    <AuthContext.Provider value={{ user, token, loading, isAuthenticated, login, logout }}>
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error("useAuth debe usarse dentro de AuthProvider");
  return ctx;
}
